CREATE OR REPLACE FUNCTION OFSERM.OTH_PLACED_COLLATERAL_PROCESSING_DATA_POPULATION(
    P_V_BATCH_ID         VARCHAR2,
    P_V_MIS_DATE         VARCHAR2,
    P_V_RUN_ID           VARCHAR2,
    P_V_PROCESS_ID       VARCHAR2,
    P_V_RUN_EXECUTION_ID VARCHAR2,
    P_N_RUN_SKEY         VARCHAR2,
    P_V_TASK_ID          VARCHAR2
) RETURN VARCHAR2 AUTHID CURRENT_USER AS

    ld_mis_date   DATE          := TO_DATE(P_V_MIS_DATE, 'YYYYMMDD');
    ln_mis_date   NUMBER        := TO_NUMBER(P_V_MIS_DATE);
    ln_run_skey   NUMBER(5)     := TO_NUMBER(SUBSTR(P_N_RUN_SKEY, 8, LENGTH(P_N_RUN_SKEY)));
    lv_run_id     VARCHAR2(64)  := SUBSTR(P_V_RUN_ID, 8, LENGTH(P_V_RUN_ID));

BEGIN

    insert /*+APPEND*/ into FSI_PLACED_COLLATERAL(N_CLEARED_TXN_BANK_ROLE_ID,N_COUNTRY_SKEY,N_MIS_DATE_SKEY,N_POSTED_COLLATERAL_SKEY,N_GAAP_SKEY,N_INSTRUMENT_SKEY,N_MARGIN_TYPE_SKEY,N_PARTY_SKEY,N_PROD_SKEY,N_CENTRAL_COUNTERPARTY_SKEY,N_COLLATERAL_FAIR_VALUE,N_COLLATERAL_TYPE_SKEY,N_EXCHANGE_RATE,N_MTM_VALUE,N_RESIDUAL_MATURITY,N_RUN_PARAMETER_SETUP_SKEY,N_RUN_SKEY,V_APPROACH_TYPE,N_ENTITY_SKEY,N_CAP_APPROACH_TYPE_SKEY,N_CAP_RECORD_TYPE_SKEY,V_RECORD_TYPE,N_STANDARD_PARTY_TYPE_SKEY,N_BASEL_PROD_TYPE_SKEY,F_CLEARED_TRANSACTION_FLAG,F_COLL_BANKRUPTCY_REMOTE_FLAG,F_COLL_COVERS_ALL_LOSSES,F_COLL_SEGREGATED_FLAG,F_EXCHANGE_TRADED_FLAG,N_REMARGIN_FREQUENCY,N_REVALUATION_FREQUENCY,V_CCY_CODE,V_MARGIN_TYPE,V_NETTING_AGREEMENT_CODE)SELECT  /*+PARALLEL (4)*/ to_char(DIM_CLEARED_TXN_BANK_ROLE.N_CLEARED_TXN_BANK_ROLE_ID),to_char(DIM_COUNTRY.N_COUNTRY_SKEY),to_char(DIM_DATES.N_DATE_SKEY),to_char(DIM_EXPOSURE.N_ACCT_SKEY),to_char(DIM_GAAP.N_GAAP_SKEY),to_char(DIM_INSTRUMENT_CONTRACT.N_INSTRUMENT_SKEY),to_char(DIM_MARGIN_TYPE.N_MARGIN_TYPE_SKEY),to_char(DIM_PARTY.N_PARTY_SKEY),to_char(DIM_PRODUCT.N_PROD_SKEY),DIM_PARTY_CCP.N_PARTY_SKEY,COALESCE(FSI_INSTR_VALUATION_DETAILS.N_FAIR_VALUE, STG_PLACED_COLLATERAL.N_COLLATERAL_FAIR_VALUE) * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,DIM_COLLATERAL_TYPE.N_COLLATERAL_TYPE_SKEY,FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,STG_PLACED_COLLATERAL.N_MTM_VALUE * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,(COALESCE(STG_PLACED_COLLATERAL.D_MATURITY_DATE,DIM_INSTRUMENT_CONTRACT.D_MATURITY_DATE) -STG_PLACED_COLLATERAL.FIC_MIS_DATE )/365,RUN_PARAMETERS.N_RUN_PARAMETER_SETUP_SKEY,'870',FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE,to_char(FCT_ENTITY_INFO.N_ENTITY_SKEY),to_char(FSI_CAP_APPROACH_TYPE_MASTER.N_CAP_APPROACH_TYPE_SKEY),to_char(FSI_CAP_RECORD_TYPE_MASTER.N_CAP_RECORD_TYPE_SKEY),FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE,to_char(FSI_PARTY_TYPE_CLASSIFICATION.N_STANDARD_PARTY_TYPE_SKEY),to_char(FSI_REG_PROD_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY),STG_PLACED_COLLATERAL.F_CLEARED_TRANSACTION_FLAG,STG_PLACED_COLLATERAL.F_COLL_BANKRUPTCY_REMOTE_FLAG,STG_PLACED_COLLATERAL.F_COLL_COVERS_ALL_LOSSES,STG_PLACED_COLLATERAL.F_COLL_SEGREGATED_IND,STG_PLACED_COLLATERAL.F_EXCHANGE_TRADED_FLAG,to_char(STG_PLACED_COLLATERAL.N_REMARGIN_FREQUENCY),to_char(STG_PLACED_COLLATERAL.N_REVAL_FREQUENCY),STG_PLACED_COLLATERAL.V_CCY_CODE,STG_PLACED_COLLATERAL.V_MARGIN_TYPE,STG_PLACED_COLLATERAL.V_NETTING_AGREEMENT_CODE FROM STG_PLACED_COLLATERAL INNER JOIN DIM_DATES ON STG_PLACED_COLLATERAL.FIC_MIS_DATE = to_date('20260331','YYYYMMDD') AND DIM_DATES.D_CALENDAR_DATE = to_date('20260331','YYYYMMDD') INNER JOIN DIM_EXPOSURE ON STG_PLACED_COLLATERAL.V_POSTED_COLLATERAL_ID = DIM_EXPOSURE.V_EXPOSURE_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_EXPOSURE.D_RECORD_START_DATE AND DIM_EXPOSURE.D_RECORD_END_DATE LEFT JOIN DIM_GAAP ON STG_PLACED_COLLATERAL.V_GAAP_CODE = DIM_GAAP.V_GAAP_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_GAAP.D_RECORD_START_DATE AND DIM_GAAP.D_RECORD_END_DATE LEFT JOIN DIM_PRODUCT ON STG_PLACED_COLLATERAL.V_PROD_CODE = DIM_PRODUCT.V_PROD_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PRODUCT.D_RECORD_START_DATE AND DIM_PRODUCT.D_RECORD_END_DATE LEFT JOIN DIM_PARTY ON COALESCE(STG_PLACED_COLLATERAL.V_PARTY_CODE, 'MSG') = DIM_PARTY.V_PARTY_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARTY.D_RECORD_START_DATE AND DIM_PARTY.D_RECORD_END_DATE LEFT JOIN DIM_PARTY_TYPE ON DIM_PARTY_TYPE.V_PARTY_TYPE_CODE = COALESCE(DIM_PARTY.V_PARTY_TYPE, 'MSG') AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARTY_TYPE.D_RECORD_START_DATE AND DIM_PARTY_TYPE.D_RECORD_END_DATE INNER JOIN FCT_ENTITY_INFO ON STG_PLACED_COLLATERAL.V_LV_CODE = FCT_ENTITY_INFO.V_ENTITY_CODE AND COALESCE(FCT_ENTITY_INFO.F_CAP_CONSL_ENTITY_IND, 'N') = 'Y' AND FCT_ENTITY_INFO.N_RUN_SKEY = '870' INNER JOIN DIM_BASEL_CAP_CONSL_APPR ON DIM_BASEL_CAP_CONSL_APPR.N_BASEL_CAP_CONSL_APPR_SKEY = FCT_ENTITY_INFO.N_BASEL_CAP_CONSL_APPR_SKEY AND DIM_BASEL_CAP_CONSL_APPR.V_BASEL_CAP_CONSL_APPR_CODE IN ( 'FLCS', 'PRCS' ) INNER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = '870' LEFT JOIN RUN_EXE_PARAMETERS   ON RUN_EXE_PARAMETERS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND RUN_EXE_PARAMETERS.V_PARAM_ID = 'LE' INNER JOIN DIM_ORG_STRUCTURE ON DIM_ORG_STRUCTURE.V_ENTITY_CODE = RUN_EXE_PARAMETERS.V_PARAM_VALUE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_ORG_STRUCTURE.D_RECORD_START_DATE AND DIM_ORG_STRUCTURE.D_RECORD_END_DATE LEFT JOIN RUN_EXE_PARAMETERS RUN_EXE_PARAMETERS_RCY ON RUN_EXE_PARAMETERS_RCY.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND RUN_EXE_PARAMETERS_RCY.V_PARAM_ID = 'RCY' LEFT JOIN DIM_PARTY DIM_PARTY_CCP ON COALESCE(STG_PLACED_COLLATERAL.V_CENTRAL_COUNTERPARTY_CODE, 'MSG') = DIM_PARTY_CCP.V_PARTY_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARTY_CCP.D_RECORD_START_DATE AND DIM_PARTY_CCP.D_RECORD_END_DATE LEFT JOIN DIM_CLEARED_TXN_BANK_ROLE ON STG_PLACED_COLLATERAL.V_CLEARED_TXN_BANK_ROLE_CODE = DIM_CLEARED_TXN_BANK_ROLE.V_CLEARED_TXN_BANK_ROLE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_CLEARED_TXN_BANK_ROLE.D_RECORD_START_DATE AND DIM_CLEARED_TXN_BANK_ROLE.D_RECORD_END_DATE LEFT JOIN FSI_REG_PROD_TYPE_RECLASS ON FSI_REG_PROD_TYPE_RECLASS.N_PROD_SKEY = DIM_PRODUCT.N_PROD_SKEY AND DIM_RUN.N_RUN_SKEY = FSI_REG_PROD_TYPE_RECLASS.N_RUN_SKEY AND DIM_DATES.N_DATE_SKEY = FSI_REG_PROD_TYPE_RECLASS.N_MIS_DATE_SKEY LEFT JOIN DIM_BASEL_PRODUCT_TYPE ON DIM_BASEL_PRODUCT_TYPE.N_BASEL_PROD_TYPE_SKEY = FSI_REG_PROD_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY LEFT JOIN FSI_INSTR_VALUATION_DETAILS ON FSI_INSTR_VALUATION_DETAILS.V_INSTRUMENT_CODE = STG_PLACED_COLLATERAL.V_INSTRUMENT_CODE AND to_date('20260331','YYYYMMDD') BETWEEN FSI_INSTR_VALUATION_DETAILS.D_RECORD_START_DATE AND FSI_INSTR_VALUATION_DETAILS.D_RECORD_END_DATE LEFT JOIN FSI_CAP_CURRENCY_CONVERSION ON FSI_CAP_CURRENCY_CONVERSION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND DIM_RUN.N_RUN_SKEY = FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY AND FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = STG_PLACED_COLLATERAL.V_CCY_CODE LEFT JOIN DIM_INSTRUMENT_CONTRACT ON DIM_INSTRUMENT_CONTRACT.V_INSTRUMENT_CODE = STG_PLACED_COLLATERAL.V_INSTRUMENT_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_INSTRUMENT_CONTRACT.D_RECORD_START_DATE AND DIM_INSTRUMENT_CONTRACT.D_RECORD_END_DATE LEFT JOIN FSI_CAP_RUN_EXE_PARAMETERS ON DIM_RUN.N_RUN_SKEY = FSI_CAP_RUN_EXE_PARAMETERS.N_RUN_SKEY AND DIM_DATES.n_date_skey = FSI_CAP_RUN_EXE_PARAMETERS.N_MIS_DATE_SKEY LEFT JOIN FSI_BASEL_EXEC_APPR_DETAILS ON FSI_BASEL_EXEC_APPR_DETAILS.N_MIS_DATE_SKEY = DIM_DATES.n_date_skey AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_BASEL_EXEC_APPR_DETAILS.V_RISK_SUB_TYPE = 'NONSEC' LEFT JOIN RUN_PARAMETERS ON RUN_PARAMETERS.N_MIS_DATE_SKEY = DIM_DATES.n_date_skey AND RUN_PARAMETERS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_PARAMETER_SKEY = RUN_PARAMETERS.N_RUN_PARAMETER_SKEY LEFT JOIN FSI_CAP_APPROACH_TYPE_MASTER ON FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE = FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE LEFT JOIN FSI_CAP_RECORD_TYPE_MASTER ON FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE = 'OTH_PLACED_COLL_EXP' LEFT JOIN DIM_MARGIN_TYPE ON DIM_MARGIN_TYPE.V_MARGIN_TYPE_CD = STG_PLACED_COLLATERAL.V_MARGIN_TYPE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_MARGIN_TYPE.D_RECORD_START_DATE AND DIM_MARGIN_TYPE.D_RECORD_END_DATE LEFT JOIN DIM_COLLATERAL_TYPE ON DIM_COLLATERAL_TYPE.V_COLLATERAL_TYPE_CODE = STG_PLACED_COLLATERAL.V_COLLATERAL_TYPE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_COLLATERAL_TYPE.D_RECORD_START_DATE AND DIM_COLLATERAL_TYPE.D_RECORD_END_DATE LEFT JOIN FSI_PARTY_TYPE_CLASSIFICATION ON FSI_PARTY_TYPE_CLASSIFICATION.N_PARTY_TYPE_SKEY = DIM_PARTY_TYPE.N_PARTY_TYPE_SKEY AND FSI_PARTY_TYPE_CLASSIFICATION.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_PARTY_TYPE_CLASSIFICATION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY LEFT JOIN DIM_COUNTRY ON COALESCE(STG_PLACED_COLLATERAL.V_COUNTRY_CODE, 'MSG') = DIM_COUNTRY.V_COUNTRY_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_COUNTRY.D_RECORD_START_DATE AND DIM_COUNTRY.D_RECORD_END_DATE WHERE 1=1 AND EXISTS ( SELECT 1 FROM STG_ACCT_PLACED_COLL_MAP INNER JOIN DIM_EXPOSURE DIM_DRV_EXPOSURE ON DIM_DRV_EXPOSURE.V_EXPOSURE_ID = STG_ACCT_PLACED_COLL_MAP.V_ACCOUNT_NUMBER AND to_date('20260331','YYYYMMDD') BETWEEN DIM_DRV_EXPOSURE.D_RECORD_START_DATE AND DIM_DRV_EXPOSURE.D_RECORD_END_DATE INNER JOIN FSI_CAP_DERIVATIVES ON FSI_CAP_DERIVATIVES.N_ACCT_SKEY = DIM_DRV_EXPOSURE.N_ACCT_SKEY WHERE FSI_CAP_DERIVATIVES.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_CAP_DERIVATIVES.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_CAP_DERIVATIVES.N_GAAP_SKEY = DIM_GAAP.N_GAAP_SKEY AND STG_ACCT_PLACED_COLL_MAP.V_POSTED_COLLATERAL_ID = DIM_EXPOSURE.V_EXPOSURE_ID AND STG_ACCT_PLACED_COLL_MAP.FIC_MIS_DATE = to_date('20260331','YYYYMMDD') ) AND ( ( COALESCE(STG_PLACED_COLLATERAL.D_MATURITY_DATE,DIM_INSTRUMENT_CONTRACT.D_MATURITY_DATE) -STG_PLACED_COLLATERAL.FIC_MIS_DATE ) /365 ) >0 LOG ERRORS INTO FSI_PLACED_COLLATERAL$ ('1776768447680_60337244_20260331_1_Job_7b32643b6c4f4ca7940316673e580c9e') REJECT LIMIT 0;

    COMMIT;
    RETURN 'OK';

EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        RETURN 'FAIL: ' || SQLERRM;
END;
